SELECT 
    id, user_id, username, module, operation, method, url, 
    params, result, status, ip, duration, operation_time
FROM operation_log


        AND username LIKE CONCAT('%', #{request.username}, '%')


        AND module LIKE CONCAT('%', #{request.module}, '%')


        AND operation LIKE CONCAT('%', #{request.operation}, '%')


        AND status = #{request.status}


        AND operation_time >= #{request.startTime}


        AND operation_time <= #{request.endTime}


ORDER BY operation_time DESC
LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM operation_log


        AND username LIKE CONCAT('%', #{request.username}, '%')


        AND module LIKE CONCAT('%', #{request.module}, '%')


        AND operation LIKE CONCAT('%', #{request.operation}, '%')


        AND status = #{request.status}


        AND operation_time >= #{request.startTime}


        AND operation_time <= #{request.endTime}
